I don't see any reason to depend on the GNU/Linux sysctl(3)-like interface. 

Vim already does this for BSD: 

long_u 
mch_total_mem(special) 
int special UNUSED; 
{ 
# ifdef __EMX__ 
return ulimit(3, 0L) >> 10;   /* always 32MB? */ 
# else 
long_u	mem = 0; 
long_u	shiftright = 10;  /* how much to shift "mem" right for Kbyte */ 

#  ifdef HAVE_SYSCTL 
int		mib[2], physmem; 
size_t	len; 

/* BSD way of getting the amount of RAM available. */ 
mib[0] = CTL_HW; 
mib[1] = HW_USERMEM; 
len = sizeof(physmem); 
if (sysctl(mib, 2, &physmem, &len, NULL, 0) == 0) 
mem = (long_u)physmem; 
#  endif 


Then code below this will overwrite 'mem' with the return from sysinfo(3), 
but only if sysctl(3) failed: 


#  if defined(HAVE_SYS_SYSINFO_H) && defined(HAVE_SYSINFO) 
if (mem == 0) 
{ 
struct sysinfo sinfo; 

/* Linux way of getting amount of RAM available */ 
if (sysinfo(&sinfo) == 0) 
{ 
#   ifdef HAVE_SYSINFO_MEM_UNIT 
/* avoid overflow as much as possible */ 
while (shiftright > 0 && (sinfo.mem_unit & 1) == 0) 
{ 
sinfo.mem_unit = sinfo.mem_unit >> 1; 
--shiftright; 
} 
mem = sinfo.totalram * sinfo.mem_unit; 
#   else 
mem = sinfo.totalram; 
#   endif 
} 
} 
#  endif 

..snip.. 


I have no reason to believe that sysctl(3) will fail, so I feel linking 
with libsysinfo is a needless dependancy that serves zero purpose.
